request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?message) AS ?messageCount)
       (SAMPLE(?messageName) AS ?exampleMessageName)
       (SAMPLE(?msgId) AS ?exampleMessageId)
WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId ?modelId .
  FILTER(STR(?modelId) = "4ac969819d6749d495c4f3be5f4745de" || STR(?modelId) = "4ac969819d6749d495c4f3be5f4745de")

  ?definitions tai:belongsTo ?model .

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?message a bboExt:Message ;
           tai:belongsTo ?choreo .

  OPTIONAL { ?message bbo:name ?messageName . }
  OPTIONAL { ?message bbo:id ?msgId . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId (COUNT(DISTINCT ?message) AS ?messageCount)
       (SAMPLE(?messageName) AS ?exampleMessageName)
       (SAMPLE(?messageId) AS ?exampleMessageId)
WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }

  FILTER(
    (BOUND(?normId) && STR(?normId) = "4ac969819d6749d495c4f3be5f4745de") ||
    (BOUND(?origId) && STR(?origId) = "4ac969819d6749d495c4f3be5f4745de")
  )

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .
  ?message a bboExt:Message ;
           tai:belongsTo ?choreo .

  OPTIONAL { ?message bbo:name ?messageName . }
  OPTIONAL { ?message bbo:id ?messageId . }
}
GROUP BY ?model ?modelName ?normId ?origId
LIMIT 25
